import { Account } from '@domain/account';
import { ApiClient } from '@service/anedot/client';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

interface IReturn {
  createAccount: (account: Partial<Account>, options?: object) => void;
  createAccountIsLoading: boolean;
}

export const useCreateAccount = (): IReturn => {
  const { t } = useTranslation('accounts');
  const { showToast } = useToast();
  const { refreshCache } = useCacheHelper(resourceKeys.accounts);

  const { isLoading, mutate } = useMutation(
    (body: Partial<Account>) => {
      return new ApiClient().post('/accounts', body);
    },
    {
      onError: () => {
        showToast({
          message: t('state.create.onError'),
          variant: 'error',
        });
      },
      onSuccess: () => {
        showToast({
          message: t('state.create.onSuccess'),
          variant: 'success',
        });

        return refreshCache('');
      },
    }
  );

  return { createAccount: mutate, createAccountIsLoading: isLoading };
};

