export const statusFilter = makeFilter<StatusFilterForm, ActionPagesQueryParams>(
  ['status'],
  { status: [] },
  ({ status }) => ({ status: status?.filter(Boolean).join(',') }),
  ({ status }) => ({ status: status ? status.split(',') : [] })
);

export const StatusFilter = () => {
  const { t } = useTranslation('actionPages', { keyPrefix: 'filter.status' });

