import { Account } from '@domain/account';
import { useEffect, useMemo, useState } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';
import { TFuncKey, useTranslation } from 'react-i18next';

export const useOrgType = () => {
  const { t: tAdmin } = useTranslation('admin');
  const { t } = useTranslation(['common', 'entityAttributes']);
  const { t: tAccount } = useTranslation('accounts');

  const { setValue } = useFormContext();
  const purpose = useWatch({ name: 'purpose' });
  const category = useWatch<Account, 'category'>({ name: 'category' });
  const subCategory = useWatch<Account, 'subCategory'>({ name: 'subCategory' });

  /* These hooks are to reset values of lower level categories so they don't stay in form
  context when the upper level category changes. Also prevents reset on initial render */
  const [initialCategory] = useState(category);
  const [initialSubCategory] = useState(subCategory);
  const [hasChangedCategory, setHasChangedCategory] = useState(false);
  const [hasChangedSubCategory, setHasChangedSubCategory] = useState(false);

  useEffect(() => {
    if (initialCategory !== category && !hasChangedCategory) {
      setHasChangedCategory(true);
    }
  }, [category, hasChangedCategory, initialCategory]);

  useEffect(() => {
    if (initialSubCategory !== subCategory && !hasChangedSubCategory) {
      setHasChangedSubCategory(true);
    }
  }, [hasChangedSubCategory, initialSubCategory, subCategory]);

  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    if (hasChangedCategory) {
      setValue('subCategory', '');
      setValue('subCategoryType', '');
    }
  }, [category, hasChangedCategory, setValue]);

  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    if (hasChangedSubCategory) {
      setValue('subCategoryType', '');
    }
  }, [setValue, hasChangedSubCategory, subCategory]);

  const purposeSelectOptions = useMemo(
    () =>
      purpose !== 'vendor'
        ? Object.entries(
            tAdmin(`accounts.purpose.${purpose as TFuncKey<'admin', 'accounts.purpose'>}`, {
              returnObjects: true,
            })
          ).map(([key, value]) => ({ label: value, value: key }))
        : [],
    [purpose, tAdmin]
  );

  const categoryOptions = useMemo(
    () =>
      Object.entries(
        t('entityAttributes:accountCategories', {
          returnObjects: true,
        })
      ).map(([key, value]) => ({ label: value, value: key })),

    [t]
  );

  const subCategoryOptions = useMemo(() => {
    const subCategories = !category
      ? []
      : category === 'vendor'
        ? [['vendor', 'Vendor']]
        : Object.entries(
            tAccount(`category.${category!}.subcategory`, {
              returnObjects: true,
            })
          );

    return subCategories.map(([key, value]) => ({ label: value, value: key }));
  }, [category, tAccount]);

  const educationalSubCategoryTypes = useMemo(() => {
    switch (subCategory) {
      case 'preschool':
        return tAccount('subcategoryType.preschool', { returnObjects: true });
      case 'k12':
        return tAccount('subcategoryType.k12', { returnObjects: true });
      case 'higher-education':
        return tAccount('subcategoryType.higher-education', { returnObjects: true });
      default:
        return { [subCategory || '']: subCategory || '' };
    }
  }, [subCategory, tAccount]);

  const politicalSubCategoryTypes = useMemo(() => {
    switch (subCategory) {
      case 'federal':
        return tAccount('subcategoryType.federal', { returnObjects: true });
      case 'state':
        return tAccount('subcategoryType.state', { returnObjects: true });
      case 'county':
        return tAccount('subcategoryType.county', { returnObjects: true });
      case 'local':
        return tAccount('subcategoryType.local', { returnObjects: true });
      case 'tribal':
        return tAccount('subcategoryType.tribal', { returnObjects: true });
      case 'pac':
        return tAccount('subcategoryType.pac', { returnObjects: true });
      case 'party':
        return tAccount('subcategoryType.party', { returnObjects: true });
      default:
        return { [subCategory || '']: subCategory || '' };
    }
  }, [subCategory, tAccount]);

