import { Flex } from '@chakra-ui/react';
import { matchSorter } from 'match-sorter';
import { useMemo } from 'react';
import { TFunction, useTranslation } from 'react-i18next';
import { useFieldSets } from './fieldSets';
import { ToggleSection } from './ToggleSection';
import { Field, FieldName } from './types';

type Props = {
  isReadOnly: boolean;
  searchTerm: string;
};

export const PermissionToggles = ({ isReadOnly, searchTerm }: Props) => {
  const { t } = useTranslation('settings', { keyPrefix: 'users.permissions.form.headings' });
  const { t: tFields } = useTranslation('settings', { keyPrefix: 'users.permissions.form.fields' });
  const fieldSets = useFieldSets();

  const fieldItems = useMemo(
    () =>
      fieldSets
        .map(({ fieldNames, titleKey }) => ({
          fieldNames: fieldNames.map((name) => `permissionToggles.${name}`),
          filteredFields: getSearchTermFilteredFields({ fieldNames, searchTerm, t: tFields }),
          titleKey,
        }))
        .filter(({ filteredFields }) => filteredFields.length > 0),
    [fieldSets, searchTerm, tFields]
  );

  return (
    <Flex direction="column" gap={6}>
      {fieldItems.map(({ fieldNames, filteredFields, titleKey }) => (
        <ToggleSection
          fieldNames={fieldNames}
          filteredFields={filteredFields}
          isReadOnly={isReadOnly}
          key={titleKey}
          title={t(titleKey)}
        />
      ))}
    </Flex>
  );
};

type GetSearchTermFilteredFieldsParams = {
  fieldNames: FieldName[];
  searchTerm: string;
  t: TFunction<'settings', 'users.permissions.form.fields'>;
};

const getSearchTermFilteredFields = ({
  fieldNames,
  searchTerm,
  t,
}: GetSearchTermFilteredFieldsParams) => {
  return fieldNames.reduce<Field[]>((fields, fieldName) => {
    const title = t(`${fieldName}.title` as Parameters<typeof t>[0]) as string;
    const label = t(`${fieldName}.description` as Parameters<typeof t>[0]) as string;

    if (
      matchSorter([title, label], searchTerm, { threshold: matchSorter.rankings.CONTAINS }).length
    ) {
      fields.push({
        label,
        name: `permissionToggles.${fieldName}`,
        title,
      });
    }

    return fields;
  }, []);
};

